#include<bits/stdc++.h>
using namespace std;
long long n,k,tim[100010],id=1,s[100010],a[100010],b[100010],m;
long long lowbit(long long x)
{
    return x&-x;
}
void add(long long x,long long v)
{
    for(long long i=x;i<=m;i+=lowbit(i))
    {
        if(tim[i]!=id)
        {
            tim[i]=id;
            s[i]=0;
        }
        s[i]+=v;
    }
}
long long query(long long x)
{
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        if(tim[i]!=id)
        {
            tim[i]=id;
            s[i]=0;
        }
        ans+=s[i];
    }
    return ans;
}
bool check(long long x)
{
    id++;
    long long sum=0,ans=1;
    for(long long i=1;i<=n;i++)
    {
        if(sum+query(m)-query(a[i])<=x)
        {
            sum+=query(m)-query(a[i]);
        }
        else
        {
            ans++;
            sum=0;
            id++;
        }
        add(a[i],1);
    }
    return ans<=k;
}
int main()
{
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        scanf("%lld%lld",&n,&k);
        for(long long i=1;i<=n;i++)
        {
            scanf("%lld",&a[i]);
            b[i]=a[i];
        }
        sort(b+1,b+1+n);
        m=unique(b+1,b+1+n)-b-1;
        for(long long i=1;i<=n;i++)
        {
            a[i]=lower_bound(b+1,b+1+m,a[i])-b;
        }
        long long l=0,r=1e18,best=1e18;
        while(l<=r)
        {
            long long mid=(l+r)>>1;
            if(check(mid))
            {
                r=mid-1;
                best=mid;
            }
            else
            {
                l=mid+1;
            }
        }
        printf("%lld\n",best);
    }
    return 0;
}
